/**
 * Complete the assessment and send the saved answers
 * to the existing NBHAS engine.
 */
function completeAssessment() {

    saveVisibleSectionAnswers();
    recalculateJourneyTotals();

    const answers = collectAssessmentAnswers();

    const engineResults = NBHAS.engine.evaluate(
        answers.symptomAnswers
    );

    console.log(
        'Engine results:',
        engineResults
    );

    showAnalysisScreen();

    window.setTimeout(
        function () {
            renderResults(
                engineResults,
                answers
            );
        },
        CONFIG.analysisDelay
    );
}

/**
 * Build the same answer structure used by the Phase 3 controller.
 */
function collectAssessmentAnswers() {

    const answers = {
        symptomAnswers: {},
        symptoms: [],
        totalScore: 0,
        answeredCount: 0,
        sectionScores: {}
    };

    NBHAS.journey.activeSections.forEach(
        function (section) {

            answers.sectionScores[
                section.SectionID
            ] = {
                sectionName:
                    section.SectionName,
                answeredCount: 0,
                score: 0,
                symptoms: []
            };
        }
    );

    NBHAS.symptoms
        .filter(isActive)
        .forEach(function (symptom) {

            if (
                !Object.prototype.hasOwnProperty.call(
                    NBHAS.journey.answers,
                    symptom.SymptomID
                )
            ) {
                return;
            }

            const score = Number(
                NBHAS.journey.answers[
                    symptom.SymptomID
                ]
            );

            answers.symptomAnswers[
                symptom.SymptomID
            ] = score;

            answers.symptoms.push({
                symptomID:
                    symptom.SymptomID,
                symptomName:
                    symptom.DisplayName,
                sectionID:
                    symptom.SectionID,
                score: score
            });

            answers.totalScore += score;
            answers.answeredCount += 1;

            const sectionBucket =
                answers.sectionScores[
                    symptom.SectionID
                ];

            if (sectionBucket) {

                sectionBucket.answeredCount += 1;
                sectionBucket.score += score;

                sectionBucket.symptoms.push({
                    symptomID:
                        symptom.SymptomID,
                    symptomName:
                        symptom.DisplayName,
                    score: score
                });
            }
        });

    console.log(
        'Collected assessment answers:',
        answers
    );

    return answers;
}

