/**
 * Render the existing dashboard without changing
 * the engine, renderer, or dashboard implementation.
 */
function renderResults(
    engineResults,
    answers
) {

    const options = document.getElementById(
        'nb-assessment-options'
    );

    const hero = document.querySelector(
        '.nb-assessment-hero'
    );

    const beginButton = document.querySelector(
        '.nb-assessment-button'
    );

    const intro = document.querySelector(
        '.nbhas-assessment-intro-area'
    );

    const categoryHeading = document.querySelector(
        '.nbhas-category-heading'
    );

    const app = document.getElementById(
        'nbhas-app'
    );

    if (!app) {
        return;
    }

    if (beginButton) {
        beginButton.style.display = 'none';
    }

    if (intro) {
        intro.style.display = 'none';
    }

    if (categoryHeading) {
        categoryHeading.style.display = 'none';
    }

    if (options) {
        options.style.display = 'none';
    }

    app.innerHTML = `
        <div id="nbhas-results"></div>
    `;

    /*
 * Preserve the completed assessment for reporting,
 * downloading, and email delivery.
 *
 * Both Download Report and Email Results will read
 * this same object.
 */
NBHAS.completedAssessment = {
    category:
        NBHAS.selectedAssessmentCategory,

    categoryGroup:
        NBHAS.selectedCategoryGroup,

    answers:
        answers,

    results:
        engineResults,

    completedAt:
        new Date().toISOString()
};

    if (
        typeof window.renderDashboard ===
        'function'
    ) {
        window.renderDashboard(
            engineResults,
            'nbhas-results'
        );

    } else if (
        window.NBHASRenderer &&
        typeof window.NBHASRenderer.render ===
        'function'
    ) {
        window.NBHASRenderer.render(
            engineResults,
            'nbhas-results'
        );

    } else {

        console.error(
            'No NBHAS results renderer is available.'
        );

        app.innerHTML = `
            <section class="nbhas-error-screen">

                <div class="nbhas-error-card">

                    <h2>
                        Results unavailable
                    </h2>

                    <p>
                        Your assessment was completed,
                        but the results display could not
                        be loaded.
                    </p>

                </div>

            </section>
        `;

        return;
    }

    NBHAS.journey.screen = 'results';
    NBHAS.state.resultsRendered = true;

    window.dispatchEvent(
        new CustomEvent(
            'nbhas:results',
            {
                detail: {
                    category:
                        NBHAS.selectedAssessmentCategory,
                    categoryGroup:
                        NBHAS.selectedCategoryGroup,
                    answers: answers,
                    results: engineResults
                }
            }
        )
    );

    if (hero && app.parentNode) {
        hero.insertAdjacentElement(
            'afterend',
            app
        );
    }

    if (hero) {
        hero.scrollIntoView({
            behavior: 'smooth',
            block: 'start'
        });
    } else {
        app.scrollIntoView({
            behavior: 'smooth',
            block: 'start'
        });
    }

    console.log(
        '✅ Results rendered'
    );
}


/******************************************************************************/
/* 99-utilities.js */
/******************************************************************************/

/******************************************************************************
 * Utilities (temporary)
 ******************************************************************************/

function escapeHTML(value) {
    return String(value)
        .replaceAll('&', '&amp;')
        .replaceAll('<', '&lt;')
        .replaceAll('>', '&gt;')
        .replaceAll('"', '&quot;')
        .replaceAll("'", '&#039;');
}

function isActive(record) {
    return (
        record.Active === true ||
        String(record.Active).toUpperCase() === 'TRUE' ||
        String(record.Active) === '1'
    );
}

function sortByDisplayOrder(a, b) {
    return (
        Number(a.DisplayOrder || 0) -
        Number(b.DisplayOrder || 0)
    );
}

function escapeAttribute(value) {
    return String(value ?? '')
        .replace(/&/g, '&amp;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;');
}

function cssEscape(value) {
    const stringValue = String(value ?? '');

    if (
        window.CSS &&
        typeof window.CSS.escape === 'function'
    ) {
        return window.CSS.escape(stringValue);
    }

    return stringValue.replace(
        /[^a-zA-Z0-9_-]/g,
        character => `\\${character}`
    );
}

function showAssessmentError(message) {

    console.error(message);

    const app = document.getElementById('nbhas-app');

    if (!app) {
        return;
    }

    app.innerHTML = `
        <section class="nbhas-journey-screen">
            <div class="nbhas-error">
                <h2>Something went wrong</h2>
                <p>${escapeHTML(message)}</p>

                <button
                    type="button"
                    class="nbhas-button"
                    onclick="location.reload()">
                    Start Again
                </button>
            </div>
        </section>
    `;
}

